const raw = $input.first().json;
const incoming = raw.body || raw;
const config = {
  SUPABASE_URL: 'YOUR_SUPABASE_URL',
  SUPABASE_SERVICE_KEY: 'YOUR_SUPABASE_SERVICE_KEY',
  ANTHROPIC_API_KEY: 'YOUR_ANTHROPIC_API_KEY',
  SERPER_API_KEY: 'YOUR_SERPER_API_KEY',
  GRYNOW_WEBSITE_ID: 'YOUR_GRYNOW_WEBSITE_ID',
  MYWALL_WEBSITE_ID: 'YOUR_MYWALL_WEBSITE_ID',
  MEMORY_WEBHOOK_URL: 'http://localhost:5678/webhook/seo-memory',
  REVIEW_WEBHOOK_URL: 'http://localhost:5678/webhook/seo-review',
  PIPELINE_WEBHOOK_URL: 'http://localhost:5678/webhook/seo-pipeline',
};
return [{ json: { ...config, ...incoming } }];

const fetch=(u,o={})=>new Promise((res,rej)=>{const iH=u.startsWith('https');const lib=require(iH?'https':'http');const m=u.match(/^https?:\/\/([^/:]+)(?::(\d+))?(\/[^?#]*)?(\?[^#]*)?/);if(!m)return rej(new Error('Bad URL: '+u));const body=o.body||null;const req=lib.request({hostname:m[1],port:m[2]?+m[2]:(iH?443:80),path:(m[3]||'/')+(m[4]||''),method:o.method||'GET',headers:{...(o.headers||{}),...(body?{'Content-Length':Buffer.byteLength(body)}:{})}},r=>{let d='';r.on('data',c=>d+=c);r.on('end',()=>res({ok:r.statusCode<300,status:r.statusCode,json:()=>Promise.resolve(JSON.parse(d||'null')),text:()=>Promise.resolve(d)}));});req.on('error',rej);if(body)req.write(body);req.end();});

const cfg = $('Config').first().json;

// Normalise intake — new requests are flat, rework has nested intake object
const isFlat = !!cfg.topic;
const intake = isFlat ? cfg : (cfg.intake && cfg.intake.topic ? cfg.intake : cfg);
const requestId   = cfg.request_id;
const startFrom   = cfg.start_from || 'research';
const isRework    = cfg.is_rework || false;
const reworkFb    = cfg.rework_feedback || null;
let websiteId = intake.website_slug === 'grynow' ? cfg.GRYNOW_WEBSITE_ID : cfg.MYWALL_WEBSITE_ID;

const sbUrl = cfg.SUPABASE_URL;
const sbKey = cfg.SUPABASE_SERVICE_KEY;
const sbH   = { 'apikey': sbKey, 'Authorization': 'Bearer ' + sbKey, 'Content-Type': 'application/json' };

async function sbGet(path) {
  const r = await fetch(sbUrl + '/rest/v1/' + path, { headers: { apikey: sbKey, Authorization: 'Bearer ' + sbKey } });
  return r.ok ? r.json() : [];
}
async function sbPatch(table, filter, body) {
  await fetch(`${sbUrl}/rest/v1/${table}?${filter}`, { method: 'PATCH', headers: sbH, body: JSON.stringify(body) });
}
async function claude(system, user, maxTokens) {
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': cfg.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: maxTokens || 4096, system, messages: [{ role: 'user', content: user }] })
  });
  const d = await r.json();
  if (!d.content) throw new Error('Claude error: ' + JSON.stringify(d));
  return d.content[0].text;
}
function parseJSON(text) {
  try {
    const m = text.match(/```json\s*([\s\S]*?)```/) || text.match(/({[\s\S]*})/);
    return JSON.parse(m ? m[1] : text);
  } catch(e) { return { _parse_error: true, raw: text.substring(0, 300) }; }
}

let researchBrief = cfg.research_brief || null;
let strategyBrief = cfg.strategy_brief || null;

// Self-fetch intake + briefs when called from Review Handler (rework with no intake passed)
if (startFrom === 'write' && !intake.topic && requestId) {
  const rr = await fetch(`${sbUrl}/rest/v1/content_requests?id=eq.${requestId}&select=*,websites(slug,name)`, { headers: { apikey: sbKey, Authorization: 'Bearer '+sbKey } });
  const rrows = await rr.json();
  if (rrows && rrows[0]) {
    const rreq = rrows[0];
    Object.assign(intake, {
      website_slug: rreq.websites?.slug || 'grynow',
      website_name: rreq.websites?.name || 'GryNow',
      website_url:  rreq.websites?.slug === 'grynow' ? 'https://grynow.in' : 'https://mywall.me',
      placement: rreq.placement, content_type: rreq.content_type, topic: rreq.topic,
      keywords: rreq.keywords, keywords_raw: (rreq.keywords||[]).join(', '),
      layout_notes: rreq.layout_notes||'', additional_brief: rreq.additional_brief||''
    });
    researchBrief = researchBrief || rreq.research_brief;
    strategyBrief = strategyBrief || rreq.strategy_brief;
  }
  websiteId = intake.website_slug === 'grynow' ? cfg.GRYNOW_WEBSITE_ID : cfg.MYWALL_WEBSITE_ID;
}

// ─────────────────────────────────────────────────────────── RESEARCH ──
if (startFrom !== 'write') {
  await sbPatch('content_requests', `id=eq.${requestId}`, { status: 'researching' });

  const [kbData, linksData, memData, serp, web] = await Promise.all([
    sbGet(`knowledge_base?select=category,content&or=(website_id.eq.${websiteId},website_id.is.null)`).catch(()=>[]),
    sbGet(`internal_links?select=url,title,h1&website_id=eq.${websiteId}&limit=120`).catch(()=>[]),
    sbGet(`memory_patterns?select=pattern_type,pattern&or=(website_id.eq.${websiteId},website_id.is.null)&order=frequency.desc&limit=20`).catch(()=>[]),
    fetch('https://google.serper.dev/search', { method:'POST', headers:{'X-API-KEY':cfg.SERPER_API_KEY,'Content-Type':'application/json'}, body: JSON.stringify({q: (intake.keywords||[])[0]+' '+intake.topic, num:10, gl:'in'}) }).then(r=>r.json()).catch(()=>({organic:[]})),
    fetch('https://google.serper.dev/search', { method:'POST', headers:{'X-API-KEY':cfg.SERPER_API_KEY,'Content-Type':'application/json'}, body: JSON.stringify({q: intake.topic+' statistics facts 2025', num:8}) }).then(r=>r.json()).catch(()=>({organic:[]})),
  ]);

  const kbTxt    = (Array.isArray(kbData)?kbData:[]).map(d=>`## ${d.category}\n${d.content}`).join('\n\n') || 'No KB yet.';
  const linksTxt = (Array.isArray(linksData)?linksData:[]).map(l=>`- ${l.url} | ${l.title}`).join('\n') || 'None yet.';
  const memTxt   = (Array.isArray(memData)?memData:[]).map(p=>`[${p.pattern_type}] ${p.pattern}`).join('\n') || 'None yet.';
  const serpTxt  = (serp.organic||[]).slice(0,8).map((r,i)=>`${i+1}. ${r.title} (${r.link})\n   ${r.snippet||''}`).join('\n\n');
  const webTxt   = (web.organic||[]).slice(0,6).map(r=>`- ${r.title}: ${r.snippet||''}`).join('\n');

  const rSys = `You are a Senior SEO Research Analyst for ${intake.website_name}.\nBusiness KB:\n${kbTxt}\nInternal Links:\n${linksTxt}\nMemory:\n${memTxt}`;
  const rMsg = `Brief: ${intake.content_type} | ${intake.placement} | Topic: ${intake.topic} | Keywords: ${intake.keywords_raw||''}\nLayout: ${intake.layout_notes||'None'}\nAdditional: ${intake.additional_brief||'None'}\n\nSERP:\n${serpTxt}\n\nWeb Research:\n${webTxt}\n\nReturn ONLY valid JSON:\n{"primary_keyword":"","search_intent":"informational","secondary_keywords":[],"lsi_terms":[],"competitor_analysis":[{"url":"","word_count_estimate":0,"strengths":"","gaps":""}],"avg_competitor_word_count":0,"topic_facts":[],"key_statistics":[],"audience_questions":[],"internal_links":[{"url":"","suggested_anchor":"","reason":""}],"content_gap_angle":"","differentiator":"","memory_insights":{"what_worked":"","what_to_avoid":""},"research_confidence":"high","notes_for_strategist":""}`;

  researchBrief = parseJSON(await claude(rSys, rMsg, 4096));
  await sbPatch('content_requests', `id=eq.${requestId}`, { research_brief: researchBrief, status: 'strategizing' });

  // ─────────────────────────────────────────────────────── STRATEGY ──
  const toneHint = intake.placement === 'on-page' ? 'FIRST PERSON. Brand speaks as "we"/"our".' : 'THIRD PERSON. Refer to brand by name. Never "we".';
  const sSys = `You are a Senior Content Strategist for ${intake.website_name}. Make firm editorial decisions. Return ONLY valid JSON.`;
  const sMsg = `${intake.content_type} | ${intake.placement} → ${toneHint}\nTopic: ${intake.topic}\nPrimary Keyword: ${researchBrief.primary_keyword||(intake.keywords||[])[0]||''}\nLayout Notes: ${intake.layout_notes||'None'}\n\nResearch Brief:\n${JSON.stringify(researchBrief,null,2)}\n\nReturn ONLY JSON:\n{"word_count_target":0,"word_count_rationale":"","depth":"in-depth","depth_rationale":"","tone":"","outline":[{"level":"h1","text":"","keyword":"","notes":""}],"keyword_placement_map":{"primary_keyword":{"locations":[]},"secondary_keywords":[{"keyword":"","section":""}]},"internal_links_plan":[{"url":"","anchor_text":"","placement":""}],"content_angle":"","cta_text":"","cta_placement":"end","special_instructions":"","schema_recommendation":"Article"}`;

  strategyBrief = parseJSON(await claude(sSys, sMsg, 4096));
  await sbPatch('content_requests', `id=eq.${requestId}`, { strategy_brief: strategyBrief, status: 'drafting' });
}

// ────────────────────────────────────────────────────────────── WRITE ──
const versionsRes = await sbGet(`content_versions?select=version_number&request_id=eq.${requestId}&order=version_number.desc&limit=1`);
const versionNumber = (Array.isArray(versionsRes)&&versionsRes.length) ? versionsRes[0].version_number+1 : 1;

const [kbW, patW, samW] = await Promise.all([
  sbGet(`knowledge_base?select=category,content&or=(website_id.eq.${websiteId},website_id.is.null)`).catch(()=>[]),
  sbGet(`memory_patterns?select=pattern_type,pattern&or=(website_id.eq.${websiteId},website_id.is.null)&order=frequency.desc&limit=20`).catch(()=>[]),
  sbGet(`content_archive?select=topic,content_excerpt&website_id=eq.${websiteId}&content_type=eq.${intake.content_type}&placement=eq.${intake.placement}&order=approved_at.desc&limit=3`).catch(()=>[]),
]);

const kbw = {}; (Array.isArray(kbW)?kbW:[]).forEach(d=>{ kbw[d.category]=d.content; });
const toneD = intake.placement==='on-page'
  ? `FIRST PERSON — You ARE ${intake.website_name}. Use "we","our","us". Never third person.`
  : `THIRD PERSON — Authoritative writer. Refer to ${intake.website_name} by name. NEVER "we"/"our".`;
const pos = (Array.isArray(patW)?patW:[]).filter(p=>p.pattern_type==='positive').map(p=>'- '+p.pattern).join('\n')||'Set the standard.';
const neg = (Array.isArray(patW)?patW:[]).filter(p=>p.pattern_type==='negative').map(p=>'- '+p.pattern).join('\n')||'None yet.';
const samp = (Array.isArray(samW)?samW:[]).map(s=>`Topic: ${s.topic}\nExcerpt: ${s.content_excerpt||''}`).join('\n\n---\n\n')||'No samples yet.';
const reworkSec = isRework&&reworkFb ? `\n## REWORK\nFeedback: ${reworkFb.feedback_text}\nCategory: ${reworkFb.category} | Severity: ${reworkFb.severity}\n` : '';

const wSys = `You are a Senior Content Writer for ${intake.website_name}.\n\nTONE: ${toneD}\n\nBusiness: ${kbw['business-overview']||'Digital platform.'}\nBrand Voice: ${kbw['brand-voice']||'Professional, clear, value-focused.'}\nFollow these patterns:\n${pos}\nAvoid:\n${neg}\nStyle samples:\n${samp}`;
const wMsg = `Write: ${intake.content_type} | ${intake.placement} | ${intake.topic}\nTarget words: ${(strategyBrief||{}).word_count_target||1000} (±10%)\nDepth: ${(strategyBrief||{}).depth||'in-depth'}\n${reworkSec}\nStrategy Brief:\n${JSON.stringify(strategyBrief,null,2)}\n\nWrite the full ${intake.content_type} in Markdown. Then:\n\n---METADATA---\nword_count: [exact number]\nmeta_title: [max 60 chars]\nmeta_description: [max 160 chars]\nsuggested_url_slug: [hyphenated, max 5 words]\nschema_type: [Article|HowTo|ItemList|FAQPage]\n---END METADATA---`;

const writerRaw = await claude(wSys, wMsg, 8096);

const metaMatch = writerRaw.match(/\n?---METADATA---([\s\S]*?)---END METADATA---\n?/);
const metaTxt   = metaMatch ? metaMatch[1].trim() : '';
const contentMd = writerRaw.replace(/\n?---METADATA---[\s\S]*?---END METADATA---\n?/,'').trim();
const getMeta   = key => { const m = metaTxt.match(new RegExp(key+':\\s*(.+)')); return m ? m[1].trim() : ''; };

return [{ json: {
  content_markdown: contentMd,
  word_count:       parseInt(getMeta('word_count'))||0,
  meta_title:       getMeta('meta_title'),
  meta_description: getMeta('meta_description'),
  url_slug:         getMeta('suggested_url_slug'),
  schema_type:      getMeta('schema_type'),
  version_number:   versionNumber,
  request_id:       requestId,
  intake, researchBrief, strategyBrief
}}];
